  ('heelevel3-8b44517b-moex-00115', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-112-d3ff7f6b', 'sub-heelevel3-8b44517b-06', NULL, 'single_choice', '當皮古效果（Pigoueffect）存在時，下列敘述何者正確？', '["總合供給線呈正斜率", "總合供給線呈垂直線", "總合需求線呈負斜率", "總合需求線呈水平線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:11+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "313", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
